import{_ as o,o as c,c as i,a2 as s}from"./chunks/framework.BWuWLRhz.js";const g=JSON.parse('{"title":"工作原理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/how-it-works.md","filePath":"guide/how-it-works.md","lastUpdated":1783223243000}'),t={name:"guide/how-it-works.md"};function r(d,e,a,n,l,p){return c(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="工作原理" tabindex="-1">工作原理 <a class="header-anchor" href="#工作原理" aria-label="Permalink to &quot;工作原理&quot;">​</a></h1><p>本页深入说明 CZero 从开机到执行清理的完整链路，帮助你理解它&quot;为什么这样设计&quot;。</p><h2 id="总览" tabindex="-1">总览 <a class="header-anchor" href="#总览" aria-label="Permalink to &quot;总览&quot;">​</a></h2><p>CZero 没有常驻的 Java 服务，而是把职责拆成三层：<strong>安装期</strong>准备文件，<strong>开机期</strong>拉起进程，<strong>运行期</strong>由一个 C++ 守护进程按配置调度所有任务。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>安装 (customize.sh)  ──►  开机 (service.sh → service)  ──►  运行 (timer_daemon)</span></span>
<span class="line"><span>   选语言/继承配置          初始化/改权限/拉起守护进程        读 config.json 调度清理</span></span></code></pre></div><h2 id="安装期-customize-sh" tabindex="-1">安装期：customize.sh <a class="header-anchor" href="#安装期-customize-sh" aria-label="Permalink to &quot;安装期：customize.sh&quot;">​</a></h2><p>刷入时运行一次，主要做三件事：</p><ol><li><strong>语言选择</strong> —— 通过 <code>getevent</code> 读音量键：音量上 = English，音量下 = 中文；约 60 秒无按键则默认中文。之后所有提示都用所选语言。</li><li><strong>继承旧配置</strong>（可选）—— 若选择继承且检测到旧安装，仅迁移以下用户数据，其余重置为新版默认： <ul><li><code>list/Emptyfolder/directories.prop</code>、<code>emptyfolder_white.prop</code></li><li><code>list/clean_whitelist.prop</code>、<code>list/clean_paths.prop</code></li><li><code>basis/</code> 统计目录</li><li>注意：<code>config.json</code> <strong>不继承</strong>，始终使用新版默认值。</li></ul></li><li><strong>打开项目主页</strong> —— 安装完成后拉起浏览器指向 GitHub 仓库。</li></ol><h2 id="开机期-service-sh-→-service" tabindex="-1">开机期：service.sh → service <a class="header-anchor" href="#开机期-service-sh-→-service" aria-label="Permalink to &quot;开机期：service.sh → service&quot;">​</a></h2><p>每次开机运行：</p><ol><li><code>service.sh</code> 先修正权限（目录 755，<code>.prop</code>/<code>.json</code>/<code>.log</code> 等 644），再启动 <code>service</code> 二进制，然后 <code>pkill</code> 旧的 <code>timer_daemon</code> 并用 <code>setsid</code> 重新拉起。</li><li><code>service</code>（C++）负责：更新 <code>module.prop</code> 的 <code>description</code> 显示当前状态、必要时创建 <code>basis/basis.prop</code> 统计文件、修正模块内文件权限。它<strong>不生成任何调度文件</strong> —— 调度完全由守护进程直接读 <code>config.json</code> 得出。</li></ol><h2 id="运行期-cron-timer-daemon" tabindex="-1">运行期：cron/timer_daemon <a class="header-anchor" href="#运行期-cron-timer-daemon" aria-label="Permalink to &quot;运行期：cron/timer_daemon&quot;">​</a></h2><p>这是 CZero 的核心 —— 一个用 <code>timerfd</code> + <code>epoll</code> 实现的极简 cron 引擎：</p><ul><li><strong>直接读 <code>config.json</code></strong> —— 内置 JSON 解析与 ISO8601→cron 转换，在内存里构建任务表与门控表，不落盘成中间文件。</li><li><strong>热重载</strong> —— 监视 <code>config.json</code> 的 mtime，变更后在下一分钟自动重建任务集；若配置为空或无法解析，则保留上一份有效任务集，服务不中断。</li><li><strong>固定日任务</strong> —— 额外注册一个每天 00:00 的 <code>list/zero</code> 任务（重置统计、清理非今日日志），该任务不在 <code>config.json</code> 中。</li><li><strong>逐分钟触发</strong> —— 按手机本地时间（<code>localtime_r</code>）每分钟检查一次；用 <code>posix_spawn</code> 运行脚本；若上一轮还在执行则跳过本轮（防重入）。</li><li><strong>多天任务门控</strong> —— 周期 ≥ 1 天的任务，其上次运行时间戳持久化在 <code>cron/state</code>，未满周期则跳过。</li><li><strong>单实例</strong> —— 通过 <code>cron/timer.lock</code> 防止重复启动。</li><li><strong>日志</strong> —— 与其他组件共写每日日志（标签 <code>[定时]</code>），同样受 <code>general.log</code> 开关控制。</li></ul><h2 id="一次清理是如何发生的" tabindex="-1">一次清理是如何发生的 <a class="header-anchor" href="#一次清理是如何发生的" aria-label="Permalink to &quot;一次清理是如何发生的&quot;">​</a></h2><p>以微信缓存清理为例：</p><ol><li>守护进程到点触发 <code>list/Tencent/check</code>。</li><li><code>check</code> 识别前台应用：读 <code>/dev/cpuset/top-app</code> 与 <code>dumpsys activity</code> 的 <code>ResumedActivity</code>。</li><li>判断保护条件：前台是微信本身、或前台是游戏 → 本轮跳过；否则继续。</li><li>调用对应清理器（<code>tencentmm</code> 等 Go 二进制）执行清理，受 <code>enhanced</code> 与时序屏障约束。</li><li>更新 <code>basis.prop</code> 统计，按需写日志，并可向 CZeroX 广播进度 / 结果。</li></ol><h2 id="为什么这样设计" tabindex="-1">为什么这样设计 <a class="header-anchor" href="#为什么这样设计" aria-label="Permalink to &quot;为什么这样设计&quot;">​</a></h2><ul><li><strong>无常驻服务</strong> —— 只在需要时被守护进程唤起，平时不占内存与 CPU。</li><li><strong>单一配置源 + 热重载</strong> —— 配置与行为一一对应，改完即生效，且坏配置不会拖垮服务。</li><li><strong>原生前端解耦</strong> —— CZeroX 只读写 <code>config.json</code>，与模块彻底解耦，模块不装应用也能独立运行。</li></ul>`,19)])])}const m=o(t,[["render",r]]);export{g as __pageData,m as default};
